9	const main = async () => {
10	  try {
11	    const input = JSON.parse(await readStdin());
12	    const output = run(input);
13	    process.stdout.write(JSON.stringify(output));
14	  } catch (e) {
15	    process.stderr.write(`${(e as Error).message}\n`);
16	    process.exit(1);
17	  }
18	};
