1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUM: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	  rune: 25,
9	  moonstone: 25,
10	};
11	
12	type Item = {
13	  type: string;
14	  material?: string;
15	  enchantment?: number;
16	  cursed?: boolean;
17	};
18	type QuoteStep = { op: "quote"; items: Item[] };
19	type Damage = { itemType: string; amount: number };
20	type ClaimStep = {
21	  op: "claim";
22	  policy: number;
23	  incident: { cause: string; damages: Damage[] };
24	};
25	type Step = QuoteStep | ClaimStep;
26	type Customer = { yearsWithMHPCO: number };
27	type Scenario = { customer: Customer; steps: Step[] };
28	
29	const BLOCK_SIZE = 3;
30	const BLOCK_PREMIUM = 60;
31	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
32	
33	const CURSED_RATE = 0.5;
34	const HIGH_ENCHANTMENT_THRESHOLD = 5;
35	const HIGH_ENCHANTMENT_RATE = 0.3;
36	
37	type Rule<T> = { applies: (subject: T) => boolean; rate: number };
38	
39	const sumBy = <T>(items: T[], f: (item: T) => number): number =>
40	  items.reduce((sum, item) => sum + f(item), 0);
41	
42	const sumApplicableRates = <T>(rules: Rule<T>[], subject: T): number =>
43	  sumBy(
44	    rules.filter((rule) => rule.applies(subject)),
45	    (rule) => rule.rate,
46	  );
47	
48	const enchantmentLevel = (item: Item): number => item.enchantment ?? 0;
49	
50	const isCursed = (item: Item): boolean => item.cursed === true;
51	const isHighlyEnchanted = (item: Item): boolean =>
52	  enchantmentLevel(item) >= HIGH_ENCHANTMENT_THRESHOLD;
53	
54	const SURCHARGE_RULES: Rule<Item>[] = [
55	  { applies: isCursed, rate: CURSED_RATE },
56	  { applies: isHighlyEnchanted, rate: HIGH_ENCHANTMENT_RATE },
57	];
58	
59	const countByType = (items: Item[]): Map<string, number> => {
60	  const counts = new Map<string, number>();
61	  for (const item of items) {
62	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
63	  }
64	  return counts;
65	};
66	
67	const basePremiumFor = (type: string) => {
68	  const base = BASE_PREMIUM[type];
69	  if (base === undefined) throw new Error(`Unknown item type: ${type}`);
70	  return base;
71	};
72	
73	const premiumForType = (type: string, count: number) => {
74	  if (COMPONENT_TYPES.has(type) && count === BLOCK_SIZE) {
75	    return BLOCK_PREMIUM;
76	  }
77	  return count * basePremiumFor(type);
78	};
79	
80	const surchargeForItem = (item: Item) =>
81	  basePremiumFor(item.type) * sumApplicableRates(SURCHARGE_RULES, item);
82	
83	const policyBasePremium = (items: Item[]) =>
84	  sumBy([...countByType(items)], ([type, count]) => premiumForType(type, count));
85	
86	const totalItemSurcharges = (items: Item[]) => sumBy(items, surchargeForItem);
87	
88	const FIRST_INSURANCE_RATE = 0.1;
89	const LOYALTY_THRESHOLD_YEARS = 2;
90	const LOYALTY_RATE = 0.2;
91	const FOLLOWUP_RATE = 0.15;
92	
93	type QuoteContext = { customer: Customer; stepIndex: number };
94	
95	const POLICY_DISCOUNT_RULES: Rule<QuoteContext>[] = [
96	  {
97	    applies: ({ customer }) => customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS,
98	    rate: -LOYALTY_RATE,
99	  },
100	  { applies: ({ stepIndex }) => stepIndex > 0, rate: -FOLLOWUP_RATE },
101	];
102	
103	const policyAdjustmentRate = (ctx: QuoteContext) =>
104	  FIRST_INSURANCE_RATE + sumApplicableRates(POLICY_DISCOUNT_RULES, ctx);
105	
106	const quote = (items: Item[], customer: Customer, stepIndex: number) => {
107	  const policyBase = policyBasePremium(items);
108	  const adjustment = policyBase * policyAdjustmentRate({ customer, stepIndex });
109	  const premium = policyBase + adjustment + totalItemSurcharges(items);
110	  return { premium: Math.ceil(premium) + PROCESSING_FEE };
111	};
112	
113	const INSURANCE_VALUE_MULTIPLIER = 10;
114	const DEDUCTIBLE = 100;
115	const CAP_MULTIPLIER = 2;
116	
117	const insuranceValueFor = (type: string) =>
118	  basePremiumFor(type) * INSURANCE_VALUE_MULTIPLIER;
119	
120	const insuranceSum = (items: Item[]) =>
121	  sumBy(items, (item) => insuranceValueFor(item.type));
122	
123	const HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD = 8;
124	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
125	
126	const reimbursableAmount = (item: Item, damage: Damage) =>
127	  enchantmentLevel(item) >= HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD
128	    ? damage.amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
129	    : damage.amount;
130	
131	const assertValidDamage = (damage: Damage) => {
132	  if (damage.amount < 0) {
133	    throw new Error(`Negative damage amount: ${damage.amount}`);
134	  }
135	};
136	
137	const payoutForDamage = (item: Item, damage: Damage) => {
138	  assertValidDamage(damage);
139	  return Math.max(0, reimbursableAmount(item, damage) - DEDUCTIBLE);
140	};
141	
142	type PolicyState = { items: Item[]; remainingCap: number };
143	
144	const consumeItem = (available: Item[], itemType: string): Item => {
145	  const idx = available.findIndex((i) => i.type === itemType);
146	  if (idx === -1) throw new Error(`No insured ${itemType} in policy`);
147	  return available.splice(idx, 1)[0];
148	};
149	
150	const totalPayout = (items: Item[], damages: Damage[]) => {
151	  const available = [...items];
152	  return sumBy(damages, (damage) =>
153	    payoutForDamage(consumeItem(available, damage.itemType), damage),
154	  );
155	};
156	
157	const newPolicy = (items: Item[]): PolicyState => ({
158	  items,
159	  remainingCap: insuranceSum(items) * CAP_MULTIPLIER,
160	});
161	
162	const claim = (policy: PolicyState, damages: Damage[]) => {
163	  const uncappedPayout = totalPayout(policy.items, damages);
164	  const cappedPayout = Math.min(uncappedPayout, policy.remainingCap);
165	  const payout = Math.floor(cappedPayout);
166	  policy.remainingCap -= payout;
167	  return { payout, remainingCap: policy.remainingCap };
168	};
169	
170	export const run = (input: Scenario): unknown => {
171	  const policies: PolicyState[] = [];
172	  const results = input.steps.map((step, i) => {
173	    if (step.op === "quote") {
174	      policies[i] = newPolicy(step.items);
175	      return quote(step.items, input.customer, i);
176	    }
177	    return claim(policies[step.policy], step.incident.damages);
178	  });
179	  return { results };
180	};
